mapper.select:
SELECT m.*, COALESCE(su.nickname, su.username) AS sender_name, COALESCE(ru.nickname, ru.username) AS receiver_name FROM message m LEFT JOIN user su ON m.sender_id = su.id LEFT JOIN user ru ON m.receiver_id = ru.id WHERE m.receiver_id = #{userId} AND (m.delete_by_receiver IS NULL OR m.delete_by_receiver = 0)
AND m.status = #{status}
ORDER BY m.create_time DESC
